scwin.f_gridColumnData = function (impExpClsCd, blNo, bookingNo) {
    return $c.gus.decode(impExpClsCd, "I", blNo, "O", bookingNo, "");
};

scwin.excelDown = async function(gubun) {
    var fileName = "상차요청승인현황(협력업체)";
    await $c.data.downloadGridViewExcel(gr_onReqInfo, { fileName: fileName + ".xlsx", sheetName: fileName});
};
